//   GMM    5K => $36,38 · 10K => $26,78 · 15K => $22,94 · 20K => $21,45

export type BmiRegion = 'Sierra' | 'Costa' | 'Austro'
export const BMI_REGIONES: BmiRegion[] = ['Sierra', 'Costa', 'Austro']

// Identificador de cada plan nacional
export type BmiPlanId = 'sigma' | 'innova' | 'gmm'

// ── Constantes de cálculo por plan (del Excel oficial) ──
const IMPUESTO = 0.005 // Seguro campesino 0,5%
const DESC_CONTADO = 0.09 // -9% pago de contado
const DESC_DIFERIDO = 0.05 // -5% diferido especial tarjeta

// "Otros cargos" fijos que se suman al total (tarjeta + gasto admin)
const OTROS_CARGOS: Record<BmiPlanId, number> = {
  sigma: 80, // tarjeta 50 + gasto admin 30
  innova: 80, // tarjeta 50 + gasto admin 30
  gmm: 65, // tarjeta 50 + otros 15
}

// Deducibles ofrecidos por cada plan
