// ── Motor de cotización BMI ──────────────────────────────────────────
export interface BmiPersona {
  edad: number
}

export interface BmiResultadoDeducible {
  deducible: string
  label: string
  anualNormal: number
  mensualNormal: number
  anualContado: number
  anualDiferido: number
}

// Precio base de una persona por plan/región/edad/deducible (edad clamp 0..max)
function basePersona(
  plan: BmiPlanId,
  region: BmiRegion,
  edad: number,
  deducible: string,
): number {
  const e = Math.max(0, Math.round(edad))
  if (plan === 'innova') {
    const tabla = TARIFAS_INNOVA[region]
    const clamped = Math.min(e, 105)
    return tabla[clamped] ?? 0
  }
  const tablas = plan === 'sigma' ? TARIFAS_SIGMA : TARIFAS_GMM
  const tabla = tablas[region]
  const maxAge = plan === 'gmm' ? 86 : 105
  const clamped = Math.min(e, maxAge)
  const fila = tabla[clamped]
  return fila ? fila[deducible] ?? 0 : 0
}

// Cotiza un plan+deducible para una familia.
export function cotizarBmiDeducible(
  plan: BmiPlanId,
  region: BmiRegion,
  personas: BmiPersona[],
  deducible: string,
): BmiResultadoDeducible {
  const cargos = OTROS_CARGOS[plan]
  const baseFamilia = personas.reduce(
    (sum, p) => sum + basePersona(plan, region, p.edad, deducible),
    0,
  )
  const anualNormal = (baseFamilia + cargos) * (1 + IMPUESTO)
  const anualContado = (baseFamilia * (1 - DESC_CONTADO) + cargos) * (1 + IMPUESTO)
  const anualDiferido = (baseFamilia * (1 - DESC_DIFERIDO) + cargos) * (1 + IMPUESTO)
  const r2 = (n: number) => Math.round(n * 100) / 100
  return {
    deducible,
    label: BMI_DEDUCIBLE_LABEL[deducible] ?? deducible,
    anualNormal: r2(anualNormal),
    mensualNormal: r2(anualNormal / 12),
    anualContado: r2(anualContado),
    anualDiferido: r2(anualDiferido),
  }
}

// Cotiza todos los deducibles de un plan.
export function cotizarBmiPlan(
  plan: BmiPlanId,
  region: BmiRegion,
  personas: BmiPersona[],
): BmiResultadoDeducible[] {
  return BMI_DEDUCIBLES[plan].map((d) => cotizarBmiDeducible(plan, region, personas, d))
}

// Cotiza los tres planes nacionales a la vez.
export function cotizarBmiTodos(
  region: BmiRegion,
  personas: BmiPersona[],
): Record<BmiPlanId, BmiResultadoDeducible[]> {
  return {
    sigma: cotizarBmiPlan('sigma', region, personas),
    innova: cotizarBmiPlan('innova', region, personas),
    gmm: cotizarBmiPlan('gmm', region, personas),
  }
}
